from openai import OpenAI
client = OpenAI()

def check_thread_memory(thread_id, max_tokens=100000):
    messages = client.beta.threads.messages.list(thread_id=thread_id)
    total_tokens = 0
    for msg in messages.data:
        total_tokens += len(msg.content[0].text.value) // 4  # Rough token estimate
    return {
        'thread_id': thread_id,
        'total_tokens': total_tokens,
        'over_limit': total_tokens > max_tokens,
        'message_count': len(messages.data)
    }

import datetime
from openai import OpenAI
client = OpenAI()

def detect_stale_messages(thread_id):
    messages = client.beta.threads.messages.list(thread_id=thread_id)
    cutoff = datetime.datetime.now() - datetime.timedelta(days=7)
    stale_count = sum(1 for msg in messages.data 
                     if datetime.datetime.fromisoformat(msg.created_at.replace('Z', '+00:00')) < cutoff)
    return {
        'stale_messages': stale_count,
        'total_messages': len(messages.data),
        'stale_ratio': stale_count / len(messages.data)
    }

from openai import OpenAI
client = OpenAI()

def test_thread_overflow(thread_id):
    try:
        run = client.beta.threads.runs.create(
            thread_id=thread_id,
            assistant_id='your-assistant-id',
            instructions='Respond with current date only.'
        )
        client.beta.threads.runs.wait(thread_id=thread_id, run_id=run.id, timeout=30)
        return {'status': 'pass', 'run_id': run.id}
    except Exception as e:
        return {'status': 'fail', 'error': str(e), 'likely_overflow': 'context_length_exceeded' in str(e).lower()}
